dvEngine.register({
  awake: (ctx) => {},
  start: (ctx) => {},
  
  update: (ctx) => {
    const { frame, root, props, utils, env } = ctx;
    
    // Referencias DOM (Optimización: Podrían capturarse en awake en un caso ideal)
    const container = root.getElementById('plugin-container');
    const line = root.getElementById('accent-line');
    const title = root.getElementById('title-text');
    const subtitle = root.getElementById('subtitle-text');
    const glow = root.getElementById('glow-bg');

    if (!container || !line || !title || !subtitle) return;

    // 1. Enlace de Datos Reactivos v3.4 (con fallback a campos predeterminados si faltan en preset)
    title.innerText = props.title || props.brandName || 'Ana García';
    subtitle.innerText = props.subtitle || props.brandSlogan || 'Directora';
    
    // Inyectar el Color de Marca desde el Preset al Entorno Global CSS del plugin
    container.style.setProperty('--accent', props.brandPrimaryColor || '#E44C30');

    // 2. Animación Parametrizada por el Entorno
    // Obtener la duración dinámica desde el plugin "motion" o usar 200 frames por defecto
    const totalFrames = (ctx.settings && ctx.settings.duration * ctx.settings.fps) || 200;

    // Animación de Entrada
    const lineProgress = utils.clamp(frame / 20, 0, 1);
    line.style.transform = `scaleX(${utils.easeOutCubic(lineProgress)})`;

    const titleT = utils.clamp((frame - 5) / 10, 0, 1);
    title.style.opacity = titleT.toString();
    title.style.transform = `translateY(${utils.lerp(20, 0, utils.easeOutCubic(titleT))}px)`;

    const subT = utils.clamp((frame - 10) / 10, 0, 1);
    subtitle.style.opacity = subT.toString();
    subtitle.style.transform = `translateY(${utils.lerp(20, 0, utils.easeOutCubic(subT))}px)`;

    // 3. Salida dinámica basada en el tiempo real
    const framesDeSalida = 15;
    const outT = utils.clamp((frame - (totalFrames - framesDeSalida)) / framesDeSalida, 0, 1);
    container.style.opacity = (1 - utils.easeOutCubic(outT)).toString();

    // 4. Optimización de Rendering con env.isExporting
    if (env.isExporting && glow) {
        // En algunos casos deshabilitar el filter/blur global mejora el tiempo de render 
        glow.style.backdropFilter = 'none';
        glow.style.background = 'rgba(0,0,0,0.8)'; // Fallback sólido oscuro
    }
  }
});

dvEngine.register({
    awake: (ctx) => {
        ctx._els = {
            track: ctx.root.getElementById('ticker-track'),
            text1: ctx.root.getElementById('ticker-text'),
            text2: ctx.root.getElementById('ticker-text-copy'),
            label: ctx.root.getElementById('ticker-label')
        };
        ctx._state = { x: 0 };
    },

    update: (ctx) => {
        const { frame, props, _els, _state } = ctx;

        // 1. Sincronizar Datos
        if (_els.text1) _els.text1.innerText = props.tickerText;
        if (_els.text2) _els.text2.innerText = props.tickerText;
        
        // Sincronizar color de marca con el badge
        if (_els.label) {
            _els.label.style.background = props.brandPrimaryColor || 'var(--accent)';
        }

        // 2. Lógica de Desplazamiento (Crawl)
        // Medimos el ancho de un bloque de texto para el loop
        const textWidth = _els.text1.offsetWidth + 50; // 50 es el margin-left del copy
        
        const speed = props.scrollSpeed || 4;
        _state.x -= speed;

        // Reset para loop infinito suave
        if (Math.abs(_state.x) >= textWidth) {
            _state.x = 0;
        }

        if (_els.track) {
            _els.track.style.transform = `translateX(${_state.x}px)`;
        }
    }
});

dvEngine.register({
    awake: (ctx) => {
        // [v4.0] Usando ctx.refs oficial
        ctx.refs.board    = ctx.root.getElementById('scoreboard');
        ctx.refs.teamA    = ctx.root.getElementById('team-a-name');
        ctx.refs.scoreA   = ctx.root.getElementById('team-a-score');
        ctx.refs.teamB    = ctx.root.getElementById('team-b-name');
        ctx.refs.scoreB   = ctx.root.getElementById('team-b-score');
        ctx.refs.time     = ctx.root.getElementById('match-time');
    },

    update: (ctx) => {
        const { props, refs, timeline, utils } = ctx;
        const { board, teamA, scoreA, teamB, scoreB, time } = refs;
        if (!board || !teamA) return;

        // 1. Sincronización de Datos Reactivos
        teamA.innerText  = props.teamA   || 'TEAM A';
        scoreA.innerText = props.scoreA  ?? 0;
        teamB.innerText  = props.teamB   || 'TEAM B';
        scoreB.innerText = props.scoreB  ?? 0;
        time.innerText   = props.matchTime || '1ST HALF';

        // ─── ENTRADA ────────────────────────────────────────────────
        // Tarea 5.3: El plugin tiene la responsabilidad total de sus propias transiciones.
        // El preset 'motion' provee los valores, pero el código aplica los transforms.
        const ip = timeline.introProgress;

        // Deslizamiento desde abajo con resorte
        const springVal = utils.spring(ip, 200, 22);
        board.style.opacity   = ip.toString();
        board.style.transform = `translateY(${utils.lerp(40, 0, springVal)}px)`;

        // ─── SALIDA ─────────────────────────────────────────────────
        if (timeline.isOutro) {
            const op = timeline.outroProgress;
            board.style.opacity   = (1 - op).toString();
            board.style.transform = `translateY(${utils.lerp(0, 40, utils.easeInOutCubic(op))}px)`;
        }
    }
});

